import { configureStore, createSlice } from '@reduxjs/toolkit';

// ── Search Slice ──────────────────────────────────────────────
const searchSlice = createSlice({
  name: 'search',
  initialState: {
    query: '',
    location: 'Madurai',
    results: [],
  },
  reducers: {
    setQuery: (state, action) => { state.query = action.payload; },
    setLocation: (state, action) => { state.location = action.payload; },
    setResults: (state, action) => { state.results = action.payload; },
  },
});

// ── UI Slice ──────────────────────────────────────────────────
const uiSlice = createSlice({
  name: 'ui',
  initialState: {
    isLoginOpen: false,
    isMobileMenuOpen: false,
    activeTab: 'accommodation',
  },
  reducers: {
    toggleLogin: (state) => { state.isLoginOpen = !state.isLoginOpen; },
    setLoginOpen: (state, action) => { state.isLoginOpen = action.payload; },
    toggleMobileMenu: (state) => { state.isMobileMenuOpen = !state.isMobileMenuOpen; },
    setActiveTab: (state, action) => { state.activeTab = action.payload; },
  },
});

export const { setQuery, setLocation, setResults } = searchSlice.actions;
export const { toggleLogin, setLoginOpen, toggleMobileMenu, setActiveTab } = uiSlice.actions;

export const store = configureStore({
  reducer: {
    search: searchSlice.reducer,
    ui: uiSlice.reducer,
  },
});
